var e=[{id:`L2_1`,type:`dialog`,speaker:`SPEAR_FLORA_SUMMER_NULL`,text:{KOREA:`평생 돌봐 주겠다니 내가 미쳤지...... 무르기는 늦었으니까, 적어도 똑부러지는 주인님이 되어 달라고.`,JPN:`一生面倒を見るとか言うんじゃなかった……今更なかったことにするわけにもいかないから、せめて要領のいいご主人様になってよね。`,ENG:`I must be insane, agreeing to take care of you for the rest of your life. But it's too late now. You'd better be a good master.`,TWN:`照顧一輩子？我真是瘋了……可是返回已經來不及了，那你至少做個聰明的主人吧……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SPEAR_FLORA_SUMMER_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`SPEAR_FLORA_SUMMER_NULL`,text:{KOREA:`......왜, 왜 놀라고 그래. 넌 내 하나뿐인...... 주인님이잖아.`,JPN:` ……な、何をそんなに驚くのよ。あんたは私のたった一人の……ご主人様なんでしょ？`,ENG:` W-why do you look so surprised? You're my only... master now.`,TWN:` 你、你幹嘛嚇一跳，你可是我唯一的……主人啊。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SPEAR_FLORA_SUMMER_NULL`,face:`UNIT_DESPAIR`},R:null}}}];export{e as default};